def assess(record: dict) -> str:
    required = {"case_id", "source", "stimulus", "environment", "response", "observed_ms", "target_ms", "owner"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["observed_ms"] <= record["target_ms"] and bool(record.get("owner"))) else "REJECT_QA_SCENARIO"

valid = {"case_id": "CASO-LIM-040-1A", **{"source": "ops", "stimulus": "100 req/s", "environment": "peak", "response": "serve", "observed_ms": 280, "target_ms": 300, "owner": "platform"}}
invalid = {"case_id": "CASO-LIM-040-1A", **{"source": "ops", "stimulus": "100 req/s", "environment": "peak", "response": "serve", "observed_ms": 999, "target_ms": 300, "owner": "platform"}}
incomplete = {**valid}
incomplete.pop("owner", None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

